import { useState } from 'react'
import LogoKB from '../../assets/images/LogoKB.png'

const ImageSlider = ({slides}) => {
  const [currentIndex, setCurrentUser] = useState(0);

  const sliderStyles = {
    height: "100%",
    position: "relative"
  }

  const slideStyles = {
    width: '100%',
    height: '100%',
    borderRadius: '10px',
    backgroundPosition: 'center',
    backgroundSize: "cover",
    backgroundImage: `url(${slides[currentIndex].url})`,
  }

  return (
  <div className="slider" style={sliderStyles}>
    <div style={slideStyles}></div>
  </div>
  )
};

export default ImageSlider;


<div
style={{
  display: 'flex',
  justifyContent: 'center',
  background: 'linear-gradient(to bottom, #16235e 0%, #020223 100%)',
}}
>

<Carousel height={460} width={980} yOrigin={42} yRadius={48}>
<div key={1} style={style}>
  <img alt="" src="../../assets/images/DadCoalMiner.jpg" />
</div>
<div key={2} style={style}>
  <img alt="" src="/image/2.png" />
</div>
<div key={3} style={style}>
  <img alt="" src="/image/3.png" />
</div>
<div key={4} style={style}>
  <img alt="" src="/image/4.png" />
</div>
</Carousel>
</div>
